const data = $json.body || $json.message || $json;

// Detectar canal según campos presentes
let canal = 'whatsapp';
let user = 'unknown';
let nombre = 'Cliente';
let message = '';

// Telegram
if (data.message && data.message.from) {
  canal = 'telegram';
  user = String(data.message.from.id);
  nombre = data.message.from.first_name || 'Cliente';
  message = data.message.text || '';
}
// Gmail
else if (data.from && data.subject !== undefined) {
  canal = 'email';
  user = data.from;
  nombre = data.from.split('@')[0];
  message = data.snippet || data.body || data.subject || '';
}
// WhatsApp Business
else if (data.entry || data.from || data.phone) {
  canal = 'whatsapp';
  user = data.from || data.phone || data.user || 'unknown';
  nombre = data.profile?.name || data.name || data.nombre || 'Cliente';
  message = data.message || data.text?.body || '';
}

return [{
  json: {
    user,
    nombre,
    message,
    canal,
    received_at: new Date().toISOString()
  }
}];

const faqs = $input.all();
const originalData = $('Normalizar Mensaje').first().json;

let faqContext = '';
if (faqs && faqs.length > 0 && faqs[0].json.question) {
  faqContext = faqs.map(f =>
    `P: ${f.json.question}\nR: ${f.json.answer}`
  ).join('\n\n');
} else {
  faqContext = '(No hay FAQ disponibles en este momento)';
}

return [{
  ...originalData,
  faq_context: faqContext
}];

try {
  const raw = $json.text || $json.choices?.[0]?.message?.content || '';
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON found');
  const data = JSON.parse(jsonMatch[0]);
  const prev = $('Preparar Contexto FAQ').first().json;
  return [{
    intent: data.intent || 'GENERAL',
    order_id: data.order_id || null,
    urgente: data.urgente || false,
    ai_respuesta: data.respuesta || 'No pude procesar tu consulta.',
    respuesta: data.respuesta || 'No pude procesar tu consulta.',
    canal: prev.canal,
    user: prev.user,
    nombre: prev.nombre || 'Cliente',
    message: prev.message,
    received_at: prev.received_at
  }];
} catch (e) {
  const prev = $('Preparar Contexto FAQ').first().json;
  return [{
    intent: 'GENERAL', order_id: null, urgente: false,
    ai_respuesta: 'Disculpá, hubo un error. ¿Podés reformularlo?',
    respuesta: 'Disculpá, hubo un error. ¿Podés reformularlo?',
    canal: prev.canal, user: prev.user, nombre: prev.nombre || 'Cliente',
    message: prev.message, received_at: prev.received_at, _parse_error: e.message
  }];
}

const pedidos = $input.all();
const originalData = $('Parse JSON').first().json;
if (!pedidos || pedidos.length === 0 || !pedidos[0].json.order_number) {
  return [{ ...originalData, respuesta: originalData.ai_respuesta || 'No encontré un pedido con ese número. ¿Podés verificarlo? (Ejemplo: ORD-TEST-001)' }];
}
const p = pedidos[0].json;
const statusMap = { 'pending': 'Pendiente', 'processing': 'En procesamiento', 'confirmed': 'Confirmado', 'shipped': 'Enviado', 'delivered': 'Entregado', 'no_stock': 'Sin stock', 'cancelled': 'Cancelado' };
const detalles = `\n\n--- Detalle de tu pedido ---\nOrden: ${p.order_number}\nProducto: ${p.product_name}\nCantidad: ${p.quantity}\nTotal: $${p.total_amount}\nEstado: ${statusMap[p.status] || p.status}\nFecha: ${new Date(p.received_at).toLocaleDateString('es-AR')}`;
return [{ ...originalData, respuesta: (originalData.ai_respuesta || '') + detalles }];

const ticket = $json;
const originalData = $('Parse JSON').first().json;
const prioridadLabel = { 'urgent': 'URGENTE', 'high': 'Alta', 'normal': 'Normal', 'low': 'Baja' };
const ticketInfo = `

--- Ticket registrado ---
N. de caso: #${ticket.id}
Estado: Abierto
Prioridad: ${prioridadLabel[ticket.priority] || ticket.priority}
Te contactaremos a la brevedad.`;
return [{ ...originalData, respuesta: (originalData.ai_respuesta || '') + ticketInfo, ticket_id: ticket.id }];
